/// <summary>
/// Find a record on a given temp table by the provided RecId.
/// </summary>
/// <param name = "_recId">RecId to be found.</param>
/// <param name = "_utilsTable">DocPrintMgmtUtilsTmp temp table buffer where the record should be found.</param>
/// <param name = "_forUpdate">boolean if record should be selected for update.</param>
/// <returns>DocPrintMgmtUtilsTmp record that is found.</returns>
public static DocPrintMgmtUtilsTmp find(RecId _recId, DocPrintMgmtUtilsTmp _utilsTable, boolean _forUpdate = false)
{
    _utilsTable.selectForUpdate(_forUpdate);

    if (_recId)
    {
        select firstonly _utilsTable where _utilsTable.RecId == _recId;
    }

    return _utilsTable;
}

/// <summary>
/// Initialize the print management related fields from the PrintMgmtSettings record.
/// </summary>
/// <param name = "_printMgmtSettings">PrintMgmtSettings record.</param>
public void initFromPrintMgmtSettings(PrintMgmtSettings _printMgmtSettings)
{
    this.PrintMgmtSettingsRecId = _printMgmtSettings.RecId;
    this.PrintMgmtSettingsRecVersion = _printMgmtSettings.RecVersion;
    //this.PrintSettingsDescription = _printMgmtSettings.Description == '' ? '(Original)' : _printMgmtSettings.Description;
    this.PrintSettingsDescription = _printMgmtSettings.Description;
    this.PrintSettingsNumberOfCopies = _printMgmtSettings.NumberOfCopies;
    this.PrintSettingsPriorityId = _printMgmtSettings.PriorityId;
    this.PrintJobSettings = _printMgmtSettings.PrintJobSettings;
}

/// <summary>
/// Initialize the document instance related fields from the PrintMgmtDocInstance record.
/// </summary>
/// <param name = "_docInstance">PrintMgmtDocInstance record.</param>
public void initFromPrintMgmtDocInstance(PrintMgmtDocInstance _docInstance)
{
    this.DocInstanceRecId = _docInstance.RecId;
    this.DocInstanceRecVersion = _docInstance.RecVersion;
    this.DocInstanceDocumentType = _docInstance.DocumentType;
    this.DocInstanceDocumentTypeName = enum2Str(_docInstance.DocumentType);
    this.DocInstanceName = _docInstance.Name;
    this.DocInstanceNodeType = _docInstance.NodeType;
    this.DocInstancePrintType = _docInstance.PrintType;
    this.DocInstancePriorityId = _docInstance.PriorityId;
    this.DocInstanceReferencedRecId = _docInstance.ReferencedRecId;
    this.DocInstanceReferencedTableId = _docInstance.ReferencedTableId; 
}

/// <summary>
/// Initialize the report format related fields from the PrintMgmtReportFormat record.
/// </summary>
/// <param name = "_reportFormat">PrintMgmtReportFormat record.</param>
public void initFromReportFormat(PrintMgmtReportFormat _reportFormat)
{
    if (!_reportFormat.RecId)
    {
        return;
    }

    this.FormatRecId = _reportFormat.RecId;
    this.FormatDescription = _reportFormat.Description;
    this.FormatName = _reportFormat.Name;
}

/// <summary>
/// Initialize the identification text from the PrintMgmtSettings record.
/// </summary>
/// <param name = "_printMgmtSettings">PrintMgmtSettings record</param>
public void initFromIdentificationText(PrintMgmtSettings _printMgmtSettings)
{        
    PrintMgmtIdentificationText footerText;
    select firstonly footerText where footerText.ParentId == _printMgmtSettings.RecId;

    this.IdentificationText = footerText.IdentificationText;        
}

/// <summary>
/// Update the print mgmt settings fields on the current record.
/// </summary>
/// <param name = "_printMgmtSettings">PrintMgmtSettings record</param>
public void rereadOneRecord(PrintMgmtSettings _printMgmtSettings)
{
    // PrintMgmtSettings fields
    this.initFromPrintMgmtSettings(_printMgmtSettings);

    // Footer text
    this.initFromIdentificationText(_printMgmtSettings);

    // Print destination fields
    DocPrintMgmtUtilsHelper::unpackPrintDestinationSettings(this);
}

/// <summary>
/// Populate one record based on the provided print management setting.
/// </summary>
/// <param name = "_printMgmtSettings">PrintMgmtSettings record</param>
/// <param name = "_docInstance">PrintMgmtDocInstance record</param>
/// <param name = "_reportFormat">PrintMgmtReportFormat record</param>
/// <param name = "_module">PrintMgmtNodeType module type</param>
public void fillOneRecord(PrintMgmtSettings _printMgmtSettings,
                            PrintMgmtDocInstance _docInstance,
                            PrintMgmtReportFormat _reportFormat,
                            PrintMgmtNodeType _module)
{
    this.clear();

    // PrintMgmtSettings fields
    this.initFromPrintMgmtSettings(_printMgmtSettings);

    // PrintMgmtDocInstance fields
    this.initFromPrintMgmtDocInstance(_docInstance);

    // PrintMgmtReportFormat fields
    this.initFromReportFormat(_reportFormat);

    // Print mgmt module
    this.PrintMgmtModule = _module;

    // Node-specific ID
    this.NodeSpecificId = DocPrintMgmtUtilsHelper::getNodeSpecificId(_docInstance.ReferencedTableId, _docInstance.ReferencedRecId, _printMgmtSettings.DataAreaId);   

    // Footer text
    this.initFromIdentificationText(_printMgmtSettings);

    // Print destination fields
    DocPrintMgmtUtilsHelper::unpackPrintDestinationSettings(this);

    this.insert();
}

/// <summary>
/// Populate the given DocPrintMgmtUtilsTmp table with detailed (flat, unpacked) information
/// about the related print management setting and print destination setting.
/// </summary>
/// <param name = "_tmpTable">DocPrintMgmtUtilsTmp buffer to be populated.</param>
/// <param name = "_infoTable">DocPrintMgmtInfoTmp table with document type, module and report links
/// (helper for populating the information about the print management module).</param>
/// <returns>int number of added records</returns>
public static int fillTableWithAllSettings(DocPrintMgmtUtilsTmp _tmpTable, DocPrintMgmtInfoTmp _infoTable)
{        
    int cnt = 0; 

    PrintMgmtSettings printMgmtSettings;
    PrintMgmtDocInstance docInstance;
    PrintMgmtReportFormat reportFormat, reportFormatSelected, reportFormatSystem;

    Set nodeTypesAllowedForUser = DocPrintMgmtHelper::getNodeTypesAllowedForUser();

    delete_from _tmpTable;

    while select printMgmtSettings
        join docInstance
            where docInstance.RecId == printMgmtSettings.ParentId
        join _infoTable 
            where _infoTable.DocumentType == docInstance.DocumentType
        outer join reportFormatSelected // format selected in UI
            where reportFormatSelected.RecId == printMgmtSettings.ReportFormat
        outer join reportFormatSystem   // default format for this document type
            where reportFormatSystem.DocumentType == docInstance.DocumentType
                && reportFormatSystem.System == NoYes::Yes
    {
        // Skip the modules not allowed for the current user.
        if (!nodeTypesAllowedForUser.in(_infoTable.NodeType))
        {
            continue;
        }

        // Settings in WHS and TMS modules have ReportFormat = 0, even though the format is selected 
        // in the Print mgmt setup form. In that case we will take the default format for this document type.
        reportFormat = printMgmtSettings.ReportFormat == 0 ? reportFormatSystem : reportFormatSelected;

        _tmpTable.fillOneRecord(printMgmtSettings, docInstance, reportFormat, _infoTable.NodeType);
        cnt++;
    }

    return cnt;
}

/// <summary>
/// Copied logic from Print destination form.
/// Get the info if the Template Id on the record is configured for the SSRS design.
/// </summary>
/// <returns>boolean if Template Id is SSRS design, false for Docentric design.</returns>
public boolean useSrsBuiltInDesign()
{
    return this.DestDocTemplateId == DocConstant::BuiltInSsrsDesignPlaceholder;
}

// ----------------------------------------------------------------------------------
// Docentric File print destination - fields modified
// ----------------------------------------------------------------------------------

/// <summary>
/// Copied and adjusted from Print destination form.
/// Execute the processing necessary when Docentric File print destination filename
/// is modified. This method is also called when file extension (for any of the 
/// template types, SSRS/Docentric) is modified.
/// </summary>
private void modifiedDocFileName()
{
    Filename    currentSelectedFilepath, currentSelectedFileName, currentSelectedFileType;
    Filename    newReportFilename, reportFilenameExt;
    boolean     updateOutputFilename = true;

    [currentSelectedFileName, currentSelectedFileType, currentSelectedFilepath] = Docu::splitFilename(this.DestDocFileName);        

    // Output filename and format
    if (this.useSrsBuiltInDesign())
    {
        reportFilenameExt = DocFileMngHelper::convertSrsFileFormatToFileExtensionStr(this.DestDocFileFormatSrs);
        //updateOutputFilename = true;
    }
    else
    {
        reportFilenameExt = DocFileMngHelper::convertToFileExtensionStr(this.DestDocFileFormat);
        //updateOutputFilename = reportFilenameExt != DocConstantFile::FileExtXml || !currentSelectedFileType;
    }

    if (currentSelectedFileName)
    {
        // Change the report output filename to have the correct file extenstion which matches the selected output file format.
        if ((currentSelectedFileType != reportFilenameExt) && updateOutputFilename)
        {
            newReportFilename = currentSelectedFileName + DocConstantFile::FileExtensionDelimiter + reportFilenameExt;
            this.DestDocFileName = newReportFilename;
        }
    }
    else
    {
        this.DestDocFileName = '';
    }

    // Azure blob, Azure files
    if (this.DestDocFileSaveToAzureBlob)
    {
        this.modifiedAzureBlobPath();
    }
    if (this.DestDocFileSaveToAzureFiles)
    {
        this.modifiedAzureFilesFolderPath();
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric File print destination / Azure Blob storage account ID is modified.
/// </summary>
private void modifiedAzureBlobPath()
{
    str blobPath = this.DestDocFileAzureBlobPath;
    if (blobPath != '')
    {
        if (strStartsWith(blobPath, DocConstantFile::AzureBlobStorageVirtualDirectoryDelimiter) &&
            !strStartsWith(blobPath, DocConstantFile::AzureBlobStorageVirtualDirectoryDelimiter + DocConstantFile::AzureBlobStorageVirtualDirectoryDelimiter))
        {
            blobPath = subStr(blobPath, 2, strLen(blobPath) - 1);
        }
    }

    this.DestDocFileAzureBlobPath = blobPath;
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric File print destination / Azure Files folder path is modified. 
/// </summary>
private void modifiedAzureFilesFolderPath()
{
    str filePath = this.DestDocFileAzureFilesFolderPath;
    if (filePath != '')
    {
        if (strStartsWith(filePath, DocConstantFile::AzureFilesDirectoryPathDelimiter) &&
            !strStartsWith(filePath, DocConstantFile::AzureFilesDirectoryPathDelimiter + DocConstantFile::AzureFilesDirectoryPathDelimiter))
        {
            filePath = subStr(filePath, 2, strLen(filePath) - 1);                    
        }
    }

    this.DestDocFileAzureFilesFolderPath = filePath;
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Azure Blob storage Account Id is modified.
/// </summary>
private void modifiedAzureBlobStorageAcount()
{
    if (this.DestDocFileAzureBlobStorageAccountId != '')
    {
        // If there is no valid licence, user will be warned, but we will still let him select an external Azure storage account.
        // Later in the pipeline we will throw the exception if the external Azure storage account is used, but the license is invalid.
        DocLicenseMng::checkLicenseUI(DocConstant::FeatureSavingToExternalAzureBlobStorage, formStr(DocPrintMgmtUtils));
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Azure Files Account Id is modified.
/// </summary>
private void modifiedAzureFilesAccountId()
{
    if (this.DestDocFileAzureFilesAccountId != '')
    {
        // If there is no valid licence, user will be warned, but we will still let him select an external Azure storage account.
        // Later in the pipeline we will throw the exception if the external Azure storage account is used, but the license is invalid.
        DocLicenseMng::checkLicenseUI(DocConstant::FeatureSavingToExternalAzureFiles, formStr(DocPrintMgmtUtils));
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when SharePoint folder path is modified.
/// </summary>
private void modifiedSharePointFolderPath()
{
    System.String sharePointFolderPath = this.DestDocFileSharePointFolderPath;        

    if (System.String::IsNullOrEmpty(sharePointFolderPath) == false)
    {
        // Checking and replacing path with / and removing trailing and leading spaces
        var pathPartElements = sharePointFolderPath.Split('/', '\\');

        sharePointFolderPath = '';
        for(int idx = 0; idx < pathPartElements.Length; idx++)
        {
            System.String pathPartElement = pathPartElements.GetValue(idx);
            // if item is empty string we skip it
            if (System.String::IsNullOrWhiteSpace(pathPartElement) == false)
            {
                sharePointFolderPath = sharePointFolderPath + pathPartElement.Trim() + '/';
            }
        }
        sharePointFolderPath = sharePointFolderPath.Trim('/');

        this.DestDocFileSharePointFolderPath = sharePointFolderPath;
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when SSRS File name or File format is modified.
/// </summary>
private void modifiedSRSFileNameOrFormat()
{
    Filename path;
    Filename name;
    Filename ext;

    if (this.DestSSRSFileName)
    {
        [path, name, ext] = fileNameSplit(this.DestSSRSFileName);

        if (name)
        {
            this.DestSSRSFileName = path + name + SRSPrintDestinationSettings::findFileNameType(this.DestSSRSFileFormat, SRSImageFileFormat::TIFF);                    
        }
        else
        {
            this.DestSSRSFileName = path;
        }
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric Email attachment name is modified.
/// </summary>
private void modifiedDocEmailAttachmentName()
{
    Filename    currentSelectedAttachmentFilepath, currentSelectedAttachmentFileName, currentSelectedAttachmentFileType;
    Filename    newAttachmentFilename, attachmentFilenameExt;
    boolean     updateOutputFilename = true;

    [currentSelectedAttachmentFileName, currentSelectedAttachmentFileType, currentSelectedAttachmentFilepath] = Docu::splitFilename(this.DestDocEmailAttachmentName);

    if (this.useSrsBuiltInDesign())
    {
        attachmentFilenameExt = DocFileMngHelper::convertSrsFileFormatToFileExtensionStr(this.DestDocEmailAttachmentFileFormatSrs);
        //updateOutputFilename = true;
    }
    else
    {
        attachmentFilenameExt = DocFileMngHelper::convertToFileExtensionStr(this.DestDocEmailAttachmentFileFormat);
        //updateOutputFilename = attachmentFilenameExt != DocConstantFile::FileExtXml || !currentSelectedAttachmentFileType;
    }

    if (this.DestDocEmailAttachmentName)
    {
        if (currentSelectedAttachmentFileType != attachmentFilenameExt && updateOutputFilename)
        {
            newAttachmentFilename = currentSelectedAttachmentFileName + DocConstantFile::FileExtensionDelimiter + attachmentFilenameExt;
            this.DestDocEmailAttachmentName = newAttachmentFilename;
        }
    }
}

