/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric Email use email template is modified.
/// </summary>
/// <param name = "_resetSelectedEmailTemplate">Should we reset the value of the SelectEmailTemplate</param>
private void modifiedUseEmailTemplate(boolean _resetSelectedEmailTemplate = true)
{
    if (this.DestDocEmailUseEmailTemplate)  // 'Use email template' is turned on
    {                                       
        // If there is no valid licence, user will be warned, but we will still let him select an email template.
        // Later in the pipeline we will throw the exception if the email template is used, but the license is invalid.
        DocLicenseMng::checkLicenseUI(DocConstant::FeatureEmailTemplates, 'DocPrintMgmtUtils');

        if (this.DestDocEmailBody != '')
        {
            BoxFormOnce boxFormOnce = BoxFormOnce::construct();
            boxFormOnce.parmDialogBoxType(DialogBoxType::YesNoBox);
            boxFormOnce.parmDialogButton(DialogButton::No);
            boxFormOnce.parmOwner(strFmt('%1 - %2 - 1', 'DocPrintMgmtUtils', DocConstant::FeatureEmailTemplates));
            boxFormOnce.parmText("@DocentricAX3:EmailTemplateSetUseEmailTemplateOn");
            boxFormOnce.parmTitle("@DocentricAX3:EmailTemplateCaption");
            if (boxFormOnce.prompt() == DialogButton::No)
            {
                this.DestDocEmailUseEmailTemplate = NoYes::No;
                this.modifiedUseEmailTemplate(false);
                return;
            }
        }

        this.DestDocEmailTemplateId = '';
        this.modifiedEmailTemplateId();
    }
    else  // 'Use email template' is turned off
    {
        if (_resetSelectedEmailTemplate)
        {
            this.DestDocEmailTemplateId = '';
            this.modifiedEmailTemplateId();
        }
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric Email email template Id is modified.
/// </summary>
private void modifiedEmailTemplateId()
{
    DocReportEmailTemplateHtmlBody htmlBody = '';

    if (this.DestDocEmailTemplateId)    // This is true when 'Use email template' is turned on.
    {
        // Get the email template record from the setup for the selected email template id.
        DocReportEmailTemplate docReportEmailTemplate = DocReportEmailTemplate::tryGetEmailTemplate(this.FormatName, this.DestDocEmailTemplateId, curExt(), currentUserLanguage());
        htmlBody = docReportEmailTemplate.HtmlBody;
    }

    this.DestDocEmailBody = htmlBody;
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric Printer to page is modified.
/// </summary>
private void modifiedPrinterToPage()
{
    if (this.DestDocPrinterPrintToPage <= 0)
    {
        this.DestDocPrinterPrintToPage = 1;
    }

    if (this.DestDocPrinterPrintToPage < this.DestDocPrinterPrintFromPage)
    {
        this.DestDocPrinterPrintToPage = this.DestDocPrinterPrintFromPage;
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric Printer from page is modified.
/// </summary>
private void modifiedPrinterFromPage()
{
    if (this.DestDocPrinterPrintFromPage <= 0)
    {
        this.DestDocPrinterPrintFromPage = 1;
    }

    if (this.DestDocPrinterPrintFromPage > this.DestDocPrinterPrintToPage)
    {
        this.DestDocPrinterPrintToPage = this.DestDocPrinterPrintFromPage;
    }
}

/// <summary>
/// Copied and adjusted from Print destination form.
/// Called when Docentric Printer number of copies is modified.
/// </summary>
private void modifiedPrinterNumberOfCopies()
{
    if (this.DestDocPrinterNumberOfCopies <= 0)
    {
        this.DestDocPrinterNumberOfCopies = 1;
    }
}

/// <summary>
/// Called when some of the values that are used for building the Print destination description
/// is modified, to force building the new description.
/// </summary>
private void modifiedPrintDestDescriptionPart()
{
    SRSPrintDestinationSettings pds = DocPrintMgmtUtilsHelper::getPackedPrintDestinationSettings(this);
    this.PrintDestinationDescription = DocSrsReportRunUtil::getPrintDestDescription(pds);
}

public void modifiedField(FieldId _fieldId)
{
    super(_fieldId);

    switch (_fieldId)
    {
        // Template
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocTemplateId)):
            this.modifiedDocFileName();
            this.modifiedDocEmailAttachmentName();
            this.modifiedPrintDestDescriptionPart();
            break;

        // Docentric File print destination, filename elements.
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileName)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileFormat)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileFormatSrs)):
            this.modifiedDocFileName();
            this.modifiedPrintDestDescriptionPart();
            break;

        // Docentric File print destination, Azure Blob
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileAzureBlobPath)):
            this.modifiedAzureBlobPath();
            break;
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileAzureBlobStorageAccountId)):
            this.modifiedAzureBlobStorageAcount();
            break;

        // Docentric File print destination, Azure Files
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileAzureFilesFolderPath)):
            this.modifiedAzureFilesFolderPath();
            break;
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileAzureFilesAccountId)):
            this.modifiedAzureFilesAccountId();
            break;

        // Docentric File print destination, SharePoint
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocFileSharePointFolderPath)):
            this.modifiedSharePointFolderPath();
            break;

        // Docentric Email print destination, email template elements.
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailUseEmailTemplate)):
            this.modifiedUseEmailTemplate();
            break;
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailTemplateId)):
            this.modifiedEmailTemplateId();
            break;

        // Docentric Email print destination, filename elements.
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailAttachmentName)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailAttachmentFileFormat)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailAttachmentFileFormatSrs)):
            this.modifiedDocEmailAttachmentName();
            this.modifiedPrintDestDescriptionPart();
            break;

        // Docentric Email print destination, email addresses (To, Cc, Bcc, From).
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailTo)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailCc)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailBcc)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailFrom)):
            this.modifiedDocEmailAddress(_fieldId);
            if (_fieldId == fieldNum(DocPrintMgmtUtilsTmp, DestDocEmailTo))
            {
                this.modifiedPrintDestDescriptionPart();
            }
            break;

        // Docentric Printer print destination
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocPrinterNumberOfCopies)):
            this.modifiedPrinterNumberOfCopies();
            break;
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocPrinterPrintFromPage)):
            this.modifiedPrinterFromPage();
            break;
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocPrinterPrintToPage)):
            this.modifiedPrinterToPage();
            break;


        // SRS File print destination
        case (fieldNum(DocPrintMgmtUtilsTmp, DestSSRSFileName)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestSSRSFileFormat)):
            this.modifiedSRSFileNameOrFormat();
            this.modifiedPrintDestDescriptionPart();
            break;
    }

    switch (_fieldId)
    {
        // If some of the fields that are combined into the Print destination description
        // is modified, then get the new description.
        // In addition to the fields handled below, also the following fields are used 
        // for building the PD description, but they are specifically handled above, 
        // so we will skip them here:
        //      DestDocTemplateId,
        //      DestDocFileName, DestDocFileFormat, 
        //      DestSSRSFileName, DestDocFileFormatSrs
        //      DestDocEmailTo
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocSaveInPrintArchive)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestDocPrinterName)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestSSRSEmailTo)):
        case (fieldNum(DocPrintMgmtUtilsTmp, DestSSRSPrinterName)):
            this.modifiedPrintDestDescriptionPart();
            break;
    }

    // Only unpacked fields are editable. When some of them is changed, 
    // set the Last modified flag accordingly.
    this.LastModifiedSetting = DocPrintMgmtUtilsLastModifiedSetting::Unpacked;

    // Mark record as dirty.
    this.RecordStatus = DocPrintMgmtUtilsRecordStatus::Dirty;
}
